import React, { useEffect, useState } from "react";
import {
  Chart as ChartJS,
  ArcElement,
  Tooltip,
  Legend,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
} from "chart.js";
import { Doughnut, Bar } from "react-chartjs-2";
import "./Dashboard.css";

ChartJS.register(ArcElement, Tooltip, Legend, CategoryScale, LinearScale, BarElement, Title);

const Dashboard = () => {
  const [stats, setStats] = useState(null);
  const [manualPeriod, setManualPeriod] = useState(null);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const res = await fetch("/api/dashboard-stats");
        const data = await res.json();
        setStats(data);
      } catch (err) {
        console.error("Error fetching stats:", err);
      }
    };
    fetchStats();
  }, []);

  const donutOptions = {
    cutout: "60%",
    plugins: {
      legend: { position: "bottom", labels: { boxWidth: 12, padding: 10 } },
      tooltip: { enabled: true },
    },
  };

  const getDonutData = (labels, values, colors) => ({
    labels,
    datasets: [{
      data: values,
      backgroundColor: colors,
      borderWidth: 0,
    }],
  });

  const barData = {
    labels: Object.keys(stats?.barChart || {}),
    datasets: [{
      label: "Free Rooms",
      data: Object.values(stats?.barChart || {}),
      backgroundColor: ["#2196F3", "#8BC34A", "#FF9800", "#03A9F4", "#E91E63"],
      barThickness: 30,
    }],
  };

  if (!stats) return <div className="loading">Loading dashboard data...</div>;

  const currentPeriodLabel = stats.currentPeriod ? `Period ${stats.currentPeriod}` : manualPeriod ? `Manual Period ${manualPeriod}` : "Outside Class Hours";

  return (
    <div className="dashboard-container">
      <h2 className="dashboard-heading">Classroom Dashboard</h2>
      <p style={{ margin: "0 0 10px 5px", fontWeight: 500 }}>{currentPeriodLabel}</p>

      {!stats.currentPeriod && (
        <div style={{ marginBottom: "15px", marginLeft: "5px" }}>
          <label>Select Period: </label>
          <select onChange={e => setManualPeriod(e.target.value)} value={manualPeriod || ""}>
            <option value="">--Select Period--</option>
            {[1, 2, 3, 4, 5, 6, 7].map(p => (
              <option key={p} value={p}>Period {p}</option>
            ))}
          </select>
        </div>
      )}

      <div className="dashboard-grid">
        <div className="card small-chart">
          <h4>Free vs Occupied</h4>
          <Doughnut
            data={getDonutData(["Occupied", "Free"], [stats.pieChart.occupied, stats.pieChart.free], ["#f44336", "#4CAF50"])}
            options={donutOptions}
          />
        </div>

        <div className="card small-chart">
          <h4>Projector Rooms</h4>
          <Doughnut
            data={getDonutData(["Projectors", "Others"], [stats.resources.projectorRooms, stats.resources.totalRooms - stats.resources.projectorRooms], ["#FF9800", "#e0e0e0"])}
            options={donutOptions}
          />
        </div>

        <div className="card small-chart">
          <h4>Free Labs</h4>
          <Doughnut
            data={getDonutData(["Labs", "Others"], [stats.resources.labs, stats.resources.totalRooms - stats.resources.labs], ["#9C27B0", "#e0e0e0"])}
            options={donutOptions}
          />
        </div>

        <div className="card small-chart">
          <h4>Free Classrooms</h4>
          <Doughnut
            data={getDonutData(["Classrooms", "Others"], [stats.resources.classrooms, stats.resources.totalRooms - stats.resources.classrooms], ["#3F51B5", "#e0e0e0"])}
            options={donutOptions}
          />
        </div>

        <div className="card small-chart">
          <h4>Not Occupied</h4>
          <Doughnut
            data={getDonutData(["Not Occupied", "Occupied"], [stats.resources.totalRooms - stats.pieChart.occupied, stats.pieChart.occupied], ["#009688", "#f44336"])}
            options={donutOptions}
          />
        </div>

        <div className="card full-width">
          <h4 style={{ marginLeft: '10px' }}>Free Rooms Per Weekday</h4>
          <div className="bar-info-container">
            <div className="bar-chart">
              <Bar
                data={barData}
                options={{
                  responsive: true,
                  maintainAspectRatio: false,
                  plugins: { legend: { display: false } },
                  scales: { y: { beginAtZero: true } },
                }}
              />
            </div>

            <div className="info-panel">
              <p><strong>Total rooms:</strong> {stats.resources.totalRooms}</p>
              <p><strong>Total labs:</strong> {stats.resources.labs}</p>
              <p><strong>Total free rooms:</strong> {stats.pieChart.free}</p>
              <p><strong>Total lab free:</strong> {stats.resources.labs}</p>
              <p><strong>Total projector free:</strong> {stats.resources.projectorRooms}</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
